17: export class ExtensionHostStarter extends Disposable implements IDisposable, IExtensionHostStarter {
18: 
19: 	readonly _serviceBrand: undefined;
20: 
21: 	private static _lastId: number = 0;
22: 
23: 	private readonly _extHosts = new Map<string, WindowUtilityProcess>();
24: 	private _shutdown = false;
25: 
26: 	constructor(
27: 		@ILogService private readonly _logService: ILogService,
28: 		@ILifecycleMainService private readonly _lifecycleMainService: ILifecycleMainService,
29: 		@IWindowsMainService private readonly _windowsMainService: IWindowsMainService,
30: 		@ITelemetryService private readonly _telemetryService: ITelemetryService,
31: 	) {
32: 		super();
33: 
34: 		// On shutdown: gracefully await extension host shutdowns
35: 		this._register(this._lifecycleMainService.onWillShutdown(e => {
36: 			this._shutdown = true;
37: 			e.join('extHostStarter', this._waitForAllExit(6000));
38: 		}));
39: 	}
40: 
41: 	override dispose(): void {
42: 		// Intentionally not killing the extension host processes
43: 		super.dispose();
44: 	}
45: 
46: 	private _getExtHost(id: string): WindowUtilityProcess {
47: 		const extHostProcess = this._extHosts.get(id);
48: 		if (!extHostProcess) {
49: 			throw new Error(`Unknown extension host!`);
50: 		}
51: 		return extHostProcess;
52: 	}
53: 
54: 	onDynamicStdout(id: string): Event<string> {
55: 		return this._getExtHost(id).onStdout;
56: 	}
57: 
58: 	onDynamicStderr(id: string): Event<string> {
59: 		return this._getExtHost(id).onStderr;
60: 	}
61: 
62: 	onDynamicMessage(id: string): Event<any> {
63: 		return this._getExtHost(id).onMessage;
64: 	}
