407: 	private _performHandshake(protocol: IMessagePassingProtocol): Promise<void> {
408: 		// 1) wait for the incoming `ready` event and send the initialization data.
409: 		// 2) wait for the incoming `initialized` event.
410: 		return new Promise<void>((resolve, reject) => {
